func tierColor(tier string) string {
	switch tier {
	case "pro":
		return "primary"
	case "enterprise":
		return "secondary"
	default:
		return "neutral"
	}
}

func billingColor(status string) string {
	switch status {
	case "active":
		return "success"
	case "past_due":
		return "warning"
	case "canceled":
		return "error"
	case "trialing":
		return "info"
	default:
		return "neutral"
	}
}

